/** Full artwork viewBox. */
const FULL_VIEWBOX = "0 0 118 38";
/** ViewBox cropped to the leading "d" glyph — the compact mark. */
const MARK_VIEWBOX = "0 3.38 24.5 25";

/** Deplo mark — the leading "d" glyph. Monochrome, theme-aware, square. */
export function DeploMark({
  className,
  size = 20,
}: {
  className?: string;
  size?: number;
}) {
  return (
    <svg
      width={size}
      height={size}
      viewBox={MARK_VIEWBOX}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={cn("text-foreground", className)}
      aria-hidden="true"
    >
      <path d={LOGO_PATH} fill="currentColor" />
    </svg>
  );
}

/** Deplo logo — the full "deplo" wordmark. Scales with the surrounding font size. */
export function DeploLogo({
  className,
  showWordmark = true,
}: {
  className?: string;
  showWordmark?: boolean;
}) {
  if (!showWordmark) return <DeploMark className={className} />;
  return (
    <svg
      viewBox={FULL_VIEWBOX}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label="Deplo"
      className={cn("h-[1.4em] w-auto text-foreground", className)}
    >
      <path d={LOGO_PATH} fill="currentColor" />
    </svg>
  );
}
